import json
from jwt import decode as jwt_decode

def verify_jwt(token):
    # Decode the JWT token
    try:
        payload = jwt_decode(token, algorithms=["HS256"])
    except Exception as e:
        print("Error decoding JWT token:", str(e))
        return None
    
    # Verify the token signature
    if not payload.get("signature"):
        print("Token does not contain a signature")
        return None
    
    # Verify the token expiration
    if not payload.get("exp"):
        print("Token does not contain an expiration claim")
        return None
    
    # Verify the token issuer
    if not payload.get("iss"):
        print("Token does not contain an issuer claim")
        return None
    
    # Verify the token audience
    if not payload.get("aud"):
        print("Token does not contain an audience claim")
        return None
    
    # Verify the token claims
    if not payload.get("claims"):
        print("Token does not contain any claims")
        return None
    
    # Return the verified JWT token
    return payload